//! CodeConnect 多语言解析器模块
//!
//! 使用 tree-sitter 对 Rust、TypeScript/JavaScript、Java、Kotlin、C# 进行 AST 解析，
//! 提取符号定义、调用关系、导入关系。
//!
//! 核心 trait:
//! - [`LanguageParser`] — 语言解析器统一接口
//! - [`ImportResolver`] — 跨文件导入解析策略

pub mod factory;
pub mod import_resolver;
pub mod query_loader;
pub mod r#trait;

// 语言解析器
pub mod csharp;
pub mod java;
pub mod javascript;
pub mod rust;
pub mod typescript;

// pub mod kotlin;  // 待 tree-sitter-kotlin grammar 就绪后启用

//! 语言解析器统一接口
//!
//! 所有语言解析器须实现此 trait，确保索引引擎能以多态方式处理不同语言。
//! 每个解析器负责：解析源码为 AST → 提取符号/调用/导入 → 输出结构化数据。

use std::path::Path;
use codeconnect_core::error::CodeConnectError;
use codeconnect_core::types::{CallSite, Import, Symbol};
use tree_sitter::Tree;

/// 语言解析器统一接口
pub trait LanguageParser: Send + Sync {
    /// 返回此解析器支持的语言名称（如 "rust", "java"）
    fn language(&self) -> &'static str;

    /// 返回此解析器支持的文件扩展名列表（如 &["rs"]）
    fn file_extensions(&self) -> &[&str];

    /// 解析源代码为 tree-sitter 语法树
    fn parse(&self, source: &str) -> Result<Tree, CodeConnectError>;

    /// 从语法树中提取所有符号定义（函数、类、结构体、变量等）
    fn extract_symbols(
        &self,
        tree: &Tree,
        source: &str,
        file_path: &Path,
    ) -> Vec<Symbol>;

    /// 从语法树中提取所有函数/方法调用点
    fn extract_calls(
        &self,
        tree: &Tree,
        source: &str,
        file_path: &Path,
    ) -> Vec<CallSite>;

    /// 从语法树中提取所有 import/use/include 语句
    fn extract_imports(
        &self,
        tree: &Tree,
        source: &str,
        file_path: &Path,
    ) -> Vec<Import>;

    /// 从文件路径和源码推断模块/包名
    fn infer_package(&self, file_path: &Path, source: &str) -> Option<String>;
}

