230	    fn extract_calls(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<CallSite> {
231	        let queries = load_rust_queries();
232	        let file_path_str = file_path.to_string_lossy().to_string();
233	        let mut results = Vec::new();
234	
235	        let query = match Query::new(&tree_sitter_rust::language(), &queries.calls) {
236	            Ok(q) => q,
237	            Err(_) => return results,
238	        };
239	
240	        let mut cursor = QueryCursor::new();
241	        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());
242	
243	        while let Some(m) = matches.next() {
244	            let mut callee_name = String::new();
245	            let mut call_type = CallType::Direct;
246	            let mut location = SourceLocation {
247	                file_path: file_path_str.clone(),
248	                line: 0,
249	                column: 0,
250	                end_line: 0,
251	                end_column: 0,
252	            };
253	
254	            for capture in m.captures {
255	                let node = capture.node;
256	                let capture_name = query.capture_names()[capture.index as usize];
257	
258	                match capture_name {
259	                    "call.name" => {
260	                        callee_name = self.node_text(node, source).to_string();
261	                    }
262	                    "call" => {
263	                        location = self.node_to_location(node);
264	                    }
265	                    "call.method" => {
266	                        call_type = CallType::Virtual; // Rust 方法调用可能通过 trait 动态分发
267	                        location = self.node_to_location(node);
268	                    }
269	                    "call.macro" => {
270	                        call_type = CallType::MacroExpansion;
271	                        location = self.node_to_location(node);
272	                    }
273	                    _ => {}
274	                }
275	            }
276	
277	            if !callee_name.is_empty() && location.line > 0 {
278	                results.push(CallSite {
279	                    caller_id: String::new(), // 由外部调用者上下文补充
280	                    callee_name,
281	                    location,
282	                    call_type,
283	                    confidence: 0.9,
284	                });
285	            }
286	        }
287	
288	        results
289	    }
