374	#[cfg(test)]
375	mod tests {
376	    use super::*;
377	    use std::path::PathBuf;
378	
379	    /// 辅助函数：创建解析器并返回解析结果
380	    fn parse_source(source: &str) -> (Tree, RustParser) {
381	        let parser = RustParser::new();
382	        let tree = parser.parse(source).expect("解析测试源码失败");
383	        (tree, parser)
384	    }
385	
386	    #[test]
387	    fn test_parse_simple_function() {
388	        let source = r#"
389	fn main() {
390	    println!("Hello, world!");
391	}
392	"#;
393	        let (tree, parser) = parse_source(source);
394	        let symbols = parser.extract_symbols(&tree, source, Path::new("test.rs"));
395	        assert!(!symbols.is_empty(), "应提取到至少一个符号");
396	        let main_fn = symbols.iter().find(|s| s.name == "main");
397	        assert!(main_fn.is_some(), "应找到 main 函数");
398	        assert_eq!(main_fn.unwrap().kind, SymbolKind::Function);
399	    }
400	
401	    #[test]
402	    fn test_parse_struct() {
403	        let source = r#"
404	pub struct Point {
405	    pub x: f64,
406	    pub y: f64,
407	}
408	"#;
409	        let (tree, parser) = parse_source(source);
410	        let symbols = parser.extract_symbols(&tree, source, Path::new("test.rs"));
411	        let point_struct = symbols.iter().find(|s| s.name == "Point");
412	        assert!(point_struct.is_some(), "应找到 Point 结构体");
413	        assert_eq!(point_struct.unwrap().kind, SymbolKind::Struct);
414	    }
