416	    #[test]
417	    fn test_parse_trait() {
418	        let source = r#"
419	pub trait Display {
420	    fn fmt(&self) -> String;
421	}
422	"#;
423	        let (tree, parser) = parse_source(source);
424	        let symbols = parser.extract_symbols(&tree, source, Path::new("test.rs"));
425	        let display_trait = symbols.iter().find(|s| s.name == "Display");
426	        assert!(display_trait.is_some(), "应找到 Display trait");
427	        assert_eq!(display_trait.unwrap().kind, SymbolKind::Trait);
428	    }
429	
430	    #[test]
431	    fn test_parse_enum() {
432	        let source = r#"
433	pub enum Color {
434	    Red,
435	    Green,
436	    Blue,
437	}
438	"#;
439	        let (tree, parser) = parse_source(source);
440	        let symbols = parser.extract_symbols(&tree, source, Path::new("test.rs"));
441	        let color_enum = symbols.iter().find(|s| s.name == "Color");
442	        assert!(color_enum.is_some(), "应找到 Color 枚举");
443	        assert_eq!(color_enum.unwrap().kind, SymbolKind::Enum);
444	    }
