446	    #[test]
447	    fn test_parse_impl_method() {
448	        let source = r#"
449	impl Point {
450	    fn new(x: f64, y: f64) -> Self {
451	        Point { x, y }
452	    }
453	}
454	"#;
455	        let (tree, parser) = parse_source(source);
456	        let symbols = parser.extract_symbols(&tree, source, Path::new("test.rs"));
457	        let new_method = symbols.iter().find(|s| s.name == "new");
458	        assert!(new_method.is_some(), "应找到 new 方法");
459	        assert_eq!(new_method.unwrap().kind, SymbolKind::Method);
