462	    #[test]
463	    fn test_parse_function_calls() {
464	        let source = r#"
465	fn main() {
466	    foo();
467	    bar.baz();
468	}
469	"#;
470	        let (tree, parser) = parse_source(source);
471	        let calls = parser.extract_calls(&tree, source, Path::new("test.rs"));
472	        let foo_call = calls.iter().find(|c| c.callee_name == "foo");
473	        let baz_call = calls.iter().find(|c| c.callee_name == "baz");
474	        assert!(foo_call.is_some(), "应有 foo 函数调用");
