508	    #[test]
509	    fn test_stable_symbol_id_format() {
510	        let id = StableSymbolId::new("rust", "src/main.rs", "function", "main");
511	        let serialized = id.to_string();
512	        // 格式: language::relative_path::kind::name::fingerprint
513	        let parts: Vec<&str> = serialized.split("::").collect();
514	        assert_eq!(parts.len(), 5, "符号 ID 应有 5 个字段");
515	        assert_eq!(parts[0], "rust");
